"""Report helper placeholders; concrete reports are generated by validation.py and visualize_results.py."""
from __future__ import annotations

from pathlib import Path
from typing import Mapping


def write_simple_html_report(path: str | Path, title: str, items: Mapping[str, str]) -> str:
    path = Path(path)
    path.parent.mkdir(parents=True, exist_ok=True)
    rows = "\n".join(f"<li><b>{k}</b>: {v}</li>" for k, v in items.items())
    path.write_text(f"<html><body><h1>{title}</h1><ul>{rows}</ul></body></html>", encoding="utf-8")
    return str(path)
